class ImagePreview extends HTMLElement{constructor(){super();this.style="display: none;"}connectedCallback(){this.addFileControlChangeListener()}disconnectedCallback(){this.removeFileControlEventListener()}addFileControlChangeListener(){const t=this.getAttribute("for"),n=document.getElementById(t);n.addEventListener("change",()=>{for(let n=this.childNodes.length-1;n>=0;n--)this.childNodes[n].tagName==="IMG"&&this.removeChild(this.childNodes[n]);if(n.files&&n.files.length>0){const r=this.getAttribute("data-class"),u=this.getAttribute("data-style"),t=document.createElement("img");t.className=r;this.appendChild(t);const i=new FileReader;i.onload=()=>{t.src=i.result,t.alt=n.files[0].name,t.style=u,t.class=r,this.style="display: inline-block"};i.readAsDataURL(n.files[0])}else this.style="display: none;"})}removeFileControlEventListener(){const n=this.getAttribute("for"),t=document.getElementById(n);t.removeEventListener()}}window.customElements.define("image-preview",ImagePreview);